import { describe, it } from "node:test";
import assert from "node:assert";
import {
  generateRunId, initRunDir, writeState, readState,
  writeStepOutput, buildResult, formatResult, aggregateUsage,
} from "./state.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import type { ExecutionState, WorkflowSpec, StepResult, StepUsage } from "./types.ts";

describe("generateRunId", () => {
  it("includes workflow name", () => {
    const id = generateRunId("bugfix");
    assert.ok(id.startsWith("bugfix-"));
  });

  it("generates unique IDs", () => {
    const a = generateRunId("test");
    const b = generateRunId("test");
    assert.notStrictEqual(a, b);
  });
});

describe("initRunDir", () => {
  it("creates directory structure", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    const runDir = initRunDir(tmpDir, "test-run-1");

    assert.ok(fs.existsSync(runDir));
    assert.ok(fs.existsSync(path.join(runDir, "sessions")));
    assert.ok(fs.existsSync(path.join(runDir, "outputs")));

    fs.rmSync(tmpDir, { recursive: true });
  });
});

describe("writeState / readState", () => {
  it("round-trips execution state", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    const runDir = path.join(tmpDir, "run");
    fs.mkdirSync(runDir, { recursive: true });

    const state: ExecutionState = {
      input: { description: "test" },
      steps: {},
      status: "running",
    };

    writeState(runDir, state);
    const loaded = readState(runDir);
    assert.deepStrictEqual(loaded, state);

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("returns null for nonexistent state", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    assert.strictEqual(readState(tmpDir), null);
    fs.rmSync(tmpDir, { recursive: true });
  });
});

describe("aggregateUsage", () => {
  it("sums usage across steps", () => {
    const usage = (n: number): StepUsage => ({
      input: n * 100, output: n * 50, cacheRead: 0, cacheWrite: 0,
      cost: n * 0.01, turns: n,
    });
    const steps: Record<string, StepResult> = {
      a: { step: "a", agent: "x", status: "completed", usage: usage(1), durationMs: 1000 },
      b: { step: "b", agent: "y", status: "completed", usage: usage(2), durationMs: 2000 },
    };
    const total = aggregateUsage(steps);
    assert.strictEqual(total.input, 300);
    assert.strictEqual(total.output, 150);
    assert.strictEqual(total.turns, 3);
    assert.ok(Math.abs(total.cost - 0.03) < 0.001);
  });
});

describe("formatResult", () => {
  it("includes workflow name and step summary", () => {
    const result = buildResult(
      { name: "test", steps: { s: { agent: "a" } } } as WorkflowSpec,
      "test-run-1",
      "/tmp/run",
      {
        input: {},
        steps: {
          s: {
            step: "s", agent: "a", status: "completed",
            textOutput: "done",
            usage: { input: 100, output: 50, cacheRead: 0, cacheWrite: 0, cost: 0.01, turns: 1 },
            durationMs: 5000,
          },
        },
        status: "completed",
      },
      "completed",
    );
    const text = formatResult(result);
    assert.ok(text.includes("test"));
    assert.ok(text.includes("completed"));
    assert.ok(text.includes("$0.01") || text.includes("0.01"));
  });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { executeWorkflow } from "./workflow-executor.ts";
import type { WorkflowSpec, AgentSpec, ExecutionState } from "./types.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

// Mock ExtensionContext and ExtensionAPI for testing
function mockCtx(cwd: string) {
  return {
    cwd,
    hasUI: false,
    ui: {
      setWidget: () => {},
      notify: () => {},
      setStatus: () => {},
    },
    // ... other ctx fields as needed (most unused in headless mode)
  } as any;
}

function mockPi() {
  const messages: any[] = [];
  return {
    sendMessage: (msg: any, opts: any) => messages.push({ msg, opts }),
    _messages: messages,
  } as any;
}

// Skip if pi is not available
let hasPi = false;
try {
  const { execSync } = await import("node:child_process");
  execSync("pi --version", { stdio: "ignore" });
  hasPi = true;
} catch {}

describe("executeWorkflow", { skip: !hasPi ? "pi not available" : undefined }, () => {
  it("runs a single-step workflow", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test workflow",
      steps: {
        greet: { agent: "default" },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const pi = mockPi();
    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi,
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "completed");
    assert.ok(result.steps.greet);
    assert.strictEqual(result.steps.greet.status, "completed");
    assert.ok(result.totalDurationMs > 0);
    assert.ok(pi._messages.length >= 1); // sendMessage called

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });

  it("fails fast on step failure", async () => {
    // Use a pre-aborted signal to reliably trigger failure on the first step.
    // pi does not necessarily fail for unknown agent names, so the original
    // approach of using a nonexistent agent is not reliable. An already-aborted
    // signal exercises the executor's cancellation/fail-fast path: the first
    // step is marked failed with "Workflow cancelled" and the second step
    // is never reached.
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: {
        willFail: { agent: "default" },
        shouldNotRun: { agent: "default" },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const controller = new AbortController();
    controller.abort(); // pre-abort

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      signal: controller.signal,
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "failed");
    assert.ok(result.steps.willFail);
    assert.strictEqual(result.steps.willFail.error, "Workflow cancelled");
    assert.ok(!result.steps.shouldNotRun); // never executed

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 30000 });

  it("validates workflow input", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      input: {
        type: "object",
        required: ["name"],
        properties: { name: { type: "string" } },
      },
      steps: { s: { agent: "default" } },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    await assert.rejects(
      () => executeWorkflow(spec, { name: 123 }, {
        ctx: mockCtx(tmpDir),
        pi: mockPi(),
        loadAgent: () => ({ name: "default" }),
      }),
      (err: unknown) => err instanceof Error && err.message.includes("Validation failed"),
    );

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("resolves expressions between steps", async () => {
    // This test verifies that step 2 can reference step 1's output.
    // Since we can't easily control what pi outputs, we verify the
    // expression resolution doesn't throw and both steps complete.
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: {
        first: { agent: "default" },
        second: {
          agent: "default",
          input: { prior: "${{ steps.first.textOutput }}" },
        },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "completed");
    assert.strictEqual(Object.keys(result.steps).length, 2);

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 120000 });

  it("persists state to disk", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: { s: { agent: "default" } },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      loadAgent: () => ({ name: "default" }),
    });

    // Verify state.json exists in run directory
    const stateFile = path.join(result.runDir, "state.json");
    assert.ok(fs.existsSync(stateFile));
    const savedState = JSON.parse(fs.readFileSync(stateFile, "utf-8"));
    assert.strictEqual(savedState.status, "completed");

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { resolveExpressions, resolveExpression, ExpressionError } from "./expression.ts";
import type { ExpressionScope, CompletionScope } from "./types.ts";

const scope: ExpressionScope = {
  input: {
    description: "null pointer in login",
    maxAttempts: 3,
    tags: ["auth", "critical"],
  },
  steps: {
    diagnose: {
      step: "diagnose",
      agent: "diagnostician",
      status: "completed",
      output: {
        summary: "NPE in UserService.login()",
        rootCause: "session param is null",
        fixLocation: { file: "src/auth/user-service.ts", line: 47 },
        reproCommand: "npm test -- --grep login",
      },
      textOutput: "Found the bug...",
      usage: { input: 1000, output: 500, cacheRead: 0, cacheWrite: 0, cost: 0.03, turns: 2 },
      durationMs: 42000,
    },
  },
};

describe("resolveExpression", () => {
  it("resolves input properties", () => {
    assert.strictEqual(resolveExpression("input.description", scope), "null pointer in login");
  });

  it("resolves input number", () => {
    assert.strictEqual(resolveExpression("input.maxAttempts", scope), 3);
  });

  it("resolves step output object", () => {
    const result = resolveExpression("steps.diagnose.output", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves nested step output", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.output.fixLocation.file", scope),
      "src/auth/user-service.ts",
    );
  });

  it("resolves step metadata", () => {
    assert.strictEqual(resolveExpression("steps.diagnose.status", scope), "completed");
    assert.strictEqual(resolveExpression("steps.diagnose.usage.cost", scope), 0.03);
  });

  it("returns undefined for missing optional property on input", () => {
    assert.strictEqual(resolveExpression("input.nonexistent", scope), undefined);
  });

  it("returns undefined for missing optional property on step output", () => {
    assert.strictEqual(resolveExpression("steps.diagnose.output.missingField", scope), undefined);
  });

  it("throws on unexecuted step", () => {
    assert.throws(
      () => resolveExpression("steps.fix.output", scope),
      (err: unknown) => err instanceof ExpressionError && err.message.includes("fix"),
    );
  });

  it("throws on invalid root path", () => {
    assert.throws(
      () => resolveExpression("typo.something", scope),
      (err: unknown) => err instanceof ExpressionError,
    );
  });
});

// ── Filter tests ──

describe("resolveExpression filters", () => {
  it("applies duration filter", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.durationMs | duration", scope),
      "42s",
    );
  });

  it("applies currency filter", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.usage.cost | currency", scope),
      "$0.03",
    );
  });

  it("applies json filter", () => {
    const result = resolveExpression("steps.diagnose.output.fixLocation | json", scope);
    assert.strictEqual(typeof result, "string");
    const parsed = JSON.parse(result as string);
    assert.strictEqual(parsed.file, "src/auth/user-service.ts");
    assert.strictEqual(parsed.line, 47);
  });

  it("handles whitespace around pipe", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.durationMs  |  duration", scope),
      "42s",
    );
  });

  it("throws on unknown filter", () => {
    assert.throws(
      () => resolveExpression("steps.diagnose.durationMs | bogus", scope),
      (err: unknown) => err instanceof ExpressionError && err.message.includes("bogus"),
    );
  });

  it("applies filter in embedded expression", () => {
    const result = resolveExpressions(
      "Took ${{ steps.diagnose.durationMs | duration }}, cost ${{ steps.diagnose.usage.cost | currency }}",
      scope,
    );
    assert.strictEqual(result, "Took 42s, cost $0.03");
  });

  it("applies filter in whole-value expression", () => {
    const result = resolveExpressions("${{ steps.diagnose.durationMs | duration }}", scope);
    assert.strictEqual(result, "42s");
  });
});

// ── Wider scope (CompletionScope) tests ──

describe("resolveExpression with CompletionScope", () => {
  const completionScope: CompletionScope = {
    input: { path: "/src" },
    steps: scope.steps,
    totalUsage: { input: 1500, output: 700, cacheRead: 0, cacheWrite: 0, cost: 0.05, turns: 3 },
    totalDurationMs: 92000,
    runDir: "/tmp/runs/test-run",
    runId: "test-20260313-120000-abcd",
    workflow: "explore-summarize",
    status: "completed",
    output: "Final summary text",
  };

  it("resolves root-level completion fields", () => {
    assert.strictEqual(resolveExpression("workflow", completionScope as unknown as Record<string, unknown>), "explore-summarize");
    assert.strictEqual(resolveExpression("status", completionScope as unknown as Record<string, unknown>), "completed");
    assert.strictEqual(resolveExpression("runDir", completionScope as unknown as Record<string, unknown>), "/tmp/runs/test-run");
    assert.strictEqual(resolveExpression("runId", completionScope as unknown as Record<string, unknown>), "test-20260313-120000-abcd");
  });

  it("resolves totalUsage fields", () => {
    assert.strictEqual(
      resolveExpression("totalUsage.cost", completionScope as unknown as Record<string, unknown>),
      0.05,
    );
  });

  it("applies filters on completion fields", () => {
    assert.strictEqual(
      resolveExpression("totalDurationMs | duration", completionScope as unknown as Record<string, unknown>),
      "1m32s",
    );
    assert.strictEqual(
      resolveExpression("totalUsage.cost | currency", completionScope as unknown as Record<string, unknown>),
      "$0.05",
    );
  });

  it("still resolves input and steps from completion scope", () => {
    assert.strictEqual(
      resolveExpression("input.path", completionScope as unknown as Record<string, unknown>),
      "/src",
    );
    assert.strictEqual(
      resolveExpression("steps.diagnose.status", completionScope as unknown as Record<string, unknown>),
      "completed",
    );
  });
});

describe("resolveExpressions", () => {
  it("resolves whole-value expression preserving type", () => {
    const result = resolveExpressions("${{ steps.diagnose.output }}", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves whole-value expression preserving number", () => {
    const result = resolveExpressions("${{ input.maxAttempts }}", scope);
    assert.strictEqual(result, 3);
  });

  it("resolves whole-value expression preserving array", () => {
    const result = resolveExpressions("${{ input.tags }}", scope);
    assert.ok(Array.isArray(result));
    assert.deepStrictEqual(result, ["auth", "critical"]);
  });

  it("resolves embedded expression as string interpolation", () => {
    const result = resolveExpressions(
      "Bug in ${{ steps.diagnose.output.fixLocation.file }} at line ${{ steps.diagnose.output.fixLocation.line }}",
      scope,
    );
    assert.strictEqual(result, "Bug in src/auth/user-service.ts at line 47");
  });

  it("resolves object values recursively", () => {
    const input = {
      description: "${{ input.description }}",
      diagnosis: "${{ steps.diagnose.output }}",
      nested: {
        file: "${{ steps.diagnose.output.fixLocation.file }}",
        plain: "no expression here",
      },
    };
    const result = resolveExpressions(input, scope) as any;
    assert.strictEqual(result.description, "null pointer in login");
    assert.strictEqual(typeof result.diagnosis, "object");
    assert.strictEqual(result.nested.file, "src/auth/user-service.ts");
    assert.strictEqual(result.nested.plain, "no expression here");
  });

  it("resolves array elements", () => {
    const input = ["${{ input.description }}", "${{ input.maxAttempts }}"];
    const result = resolveExpressions(input, scope) as unknown[];
    assert.strictEqual(result[0], "null pointer in login");
    assert.strictEqual(result[1], 3);
  });

  it("passes through non-string primitives", () => {
    assert.strictEqual(resolveExpressions(42, scope), 42);
    assert.strictEqual(resolveExpressions(true, scope), true);
    assert.strictEqual(resolveExpressions(null, scope), null);
  });

  it("passes through strings with no expressions", () => {
    assert.strictEqual(resolveExpressions("plain string", scope), "plain string");
  });

  it("handles whitespace in expressions", () => {
    assert.strictEqual(
      resolveExpressions("${{   input.description   }}", scope),
      "null pointer in login",
    );
  });

  it("renders undefined as empty string in embedded expressions", () => {
    const result = resolveExpressions(
      "Question: ${{ input.nonexistent }}",
      scope,
    );
    assert.strictEqual(result, "Question: ");
  });

  it("resolves whole-value undefined for missing optional field", () => {
    const result = resolveExpressions("${{ input.nonexistent }}", scope);
    assert.strictEqual(result, undefined);
  });

  it("stringifies objects in embedded expressions", () => {
    const result = resolveExpressions(
      "Location: ${{ steps.diagnose.output.fixLocation }}",
      scope,
    );
    assert.ok(typeof result === "string");
    assert.ok((result as string).includes("src/auth/user-service.ts"));
  });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { parseAgentFrontmatter, createAgentLoader } from "./index.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

describe("parseAgentFrontmatter", () => {
  it("parses frontmatter and system prompt", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-agent-"));
    const agentPath = path.join(tmpDir, "test.md");
    fs.writeFileSync(agentPath, `---
name: test-agent
description: A test agent
model: claude-sonnet-4-6
tools: [read, bash]
thinking: low
---
You are a test agent. Do test things.
`);

    const spec = parseAgentFrontmatter(agentPath);
    assert.strictEqual(spec.name, "test-agent");
    assert.strictEqual(spec.description, "A test agent");
    assert.strictEqual(spec.model, "claude-sonnet-4-6");
    assert.deepStrictEqual(spec.tools, ["read", "bash"]);
    assert.strictEqual(spec.thinking, "low");
    assert.ok(spec.systemPrompt?.includes("test agent"));

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("handles missing frontmatter", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-agent-"));
    const agentPath = path.join(tmpDir, "plain.md");
    fs.writeFileSync(agentPath, "Just a plain markdown file with no frontmatter.");

    const spec = parseAgentFrontmatter(agentPath);
    assert.strictEqual(spec.name, "plain");

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("uses filename as name when frontmatter has no name field", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-agent-"));
    const agentPath = path.join(tmpDir, "my-agent.md");
    fs.writeFileSync(agentPath, `---
description: Agent without a name field
tools: [read]
---
System prompt here.
`);

    const spec = parseAgentFrontmatter(agentPath);
    assert.strictEqual(spec.name, "my-agent");
    assert.strictEqual(spec.description, "Agent without a name field");
    assert.deepStrictEqual(spec.tools, ["read"]);
    assert.strictEqual(spec.systemPrompt, "System prompt here.");

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("parses extensions, skills, and output fields", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-agent-"));
    const agentPath = path.join(tmpDir, "full.md");
    fs.writeFileSync(agentPath, `---
name: full-agent
extensions: [./ext1.ts, ./ext2.ts]
skills: [coding, testing]
output: result.json
---
Full agent prompt.
`);

    const spec = parseAgentFrontmatter(agentPath);
    assert.strictEqual(spec.name, "full-agent");
    assert.deepStrictEqual(spec.extensions, ["./ext1.ts", "./ext2.ts"]);
    assert.deepStrictEqual(spec.skills, ["coding", "testing"]);
    assert.strictEqual(spec.output, "result.json");

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("handles frontmatter with no trailing content", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-agent-"));
    const agentPath = path.join(tmpDir, "no-body.md");
    fs.writeFileSync(agentPath, `---
name: no-body-agent
tools: [read]
---
`);

    const spec = parseAgentFrontmatter(agentPath);
    assert.strictEqual(spec.name, "no-body-agent");
    assert.strictEqual(spec.systemPrompt, undefined);

    fs.rmSync(tmpDir, { recursive: true });
  });
});

describe("createAgentLoader", () => {
  it("loads agent from project .pi/agents/ directory", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-loader-"));
    const agentDir = path.join(tmpDir, ".pi", "agents");
    fs.mkdirSync(agentDir, { recursive: true });
    fs.writeFileSync(path.join(agentDir, "my-agent.md"), `---
name: my-agent
tools: [bash]
---
Do things.
`);

    const loader = createAgentLoader(tmpDir);
    const spec = loader("my-agent");
    assert.strictEqual(spec.name, "my-agent");
    assert.deepStrictEqual(spec.tools, ["bash"]);
    assert.ok(spec.systemPrompt?.includes("Do things"));

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("returns minimal spec when agent not found", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-loader-"));

    const loader = createAgentLoader(tmpDir);
    const spec = loader("nonexistent-agent");
    assert.strictEqual(spec.name, "nonexistent-agent");
    assert.strictEqual(spec.tools, undefined);
    assert.strictEqual(spec.systemPrompt, undefined);

    fs.rmSync(tmpDir, { recursive: true });
  });
});

